	(73, 'PARAGRAPH', '{"type":"parrafo","text":"Grupo\\nhidr\\náulico"}', NULL, NULL, NULL, '2026-06-18 11:20:53.218274', 'ES', 1, '2026-06-18 11:20:53.218274', 63),
	(74, 'PARAGRAPH', '{"type":"parrafo","text":"0\\n1.1\\nManual de\\nprácticas"}', NULL, NULL, NULL, '2026-06-18 11:20:53.220273', 'ES', 1, '2026-06-18 11:20:53.220273', 64),
	(75, 'PARAGRAPH', '{"type":"parrafo","text":"Grupo hidráulico"}', NULL, NULL, NULL, '2026-06-18 11:20:53.222273', 'ES', 1, '2026-06-18 11:20:53.222273', 65),
