	(77, 'TABLE', '{"type":"table","columns":["1","Grupo motobomba de alimentación.","6","Depósito volumétrico."],"rows":[["2","Sistema de Marcha/Paro.","7","Medida de nivel de depósito volumétricos."],["3","Estructura de aluminio.","8","Tomas de presión en aspiración e impulsión."],["4","Salida bomba.","9","Conexión de alimentación de red."],["5","Entrada depósito.","10","Válvula de regulación de caudal."]]}', NULL, NULL, NULL, '2026-06-18 11:20:53.226270', 'ES', 1, '2026-06-18 11:20:53.226270', 67),
	(78, 'TABLE', '{"type":"table","columns":["Tensión (V)","Frecuencia (Hz)","Amperaje (A)","Altura manométrica mínima (M.C.A)","Altura manométrica máxima (M.C.A)","Caudal mínimo (l/min)","Caudal máximo (l/min)","Potencia (w)","Velocidad de giro (rpm)"],"rows":[["220-240","50","6","14","32","10","150","0,75","2900"],["","60","6.5","10","35","","200","","3450"],["110","50","12","14","32","","150","","2900"],["","60","13","10","35","","200","","3450"]]}', NULL, NULL, NULL, '2026-06-18 11:20:53.229268', 'ES', 2, '2026-06-18 11:20:53.229268', 67),
