	(282, 'PARAGRAPH', '{"type":"parrafo","text":"El equipo esta compuesto por modulos, sensores, conexiones y elementos de control."}', NULL, NULL, NULL, '2026-06-22 09:24:31.402373', 'ES', 1, '2026-06-22 09:24:31.402373', 206),
