	(284, 'PARAGRAPH', '{"type":"parrafo","text":"Comprobar las conexiones antes de iniciar la practica. Registrar los datos obtenidos durante el funcionamiento."}', NULL, NULL, NULL, '2026-06-22 09:24:31.406371', 'ES', 1, '2026-06-22 09:24:31.406371', 208),
