	(1, b'0', '001', '', 'Esta es una nota de prueba para añadir dentro de algún texto en el manual.', '2026-06-18 12:04:34.099348', '', 'Nota', NULL, '', '', 'Fluidos', 'NOTE', '2026-06-22 09:06:21.265331'),
	(2, b'0', 'NOTA-002', '', 'Otra pueba', '2026-06-18 12:05:17.763037', '', 'Nota', NULL, NULL, NULL, 'Nota', 'NOTE', '2026-06-22 09:06:24.641818'),
	(3, b'1', 'NOTA-003', NULL, 'En este equipo, el rango de funcionamiento del reóstato está limitado entre un 10 y un 90% para así evitar que la resistencia alcance valores.', '2026-06-22 11:15:30.325263', NULL, 'Nota', NULL, NULL, NULL, 'Rango de funcionamiento del reóstato', 'NOTE', '2026-06-23 10:17:54.782522'),
	(4, b'1', 'NOTA-004', NULL, 'Antes de poner en marcha el software, los dos USB de panel de control y de monitor de red monofásica, deben estar conectados al PC. De lo contrario, el programa no será capaz de realizar la conexión correctamente, y los datos pueden no mostrarse.', '2026-06-22 11:16:41.501603', NULL, 'Nota', NULL, NULL, NULL, 'USB deben estar conectados al PC', 'NOTE', NULL),
	(5, b'1', 'NOTA-005', 'Modified content from note editor', 'Contenido modificado desde editor de notas otra vez', '2026-06-22 11:19:26.399108', 'DYNAMIC NOTE TEST', 'Nota', 'Note', NULL, NULL, 'PRUEBA NOTA DINAMICA', 'NOTE', '2026-06-23 10:55:40.575147');
