	(1, b'1', 'Practicas', NULL, 'FLB10.1', '2026-06-17 11:22:16.861594', 'Producto demo para manual de practicas.', 'Producto demo para manual de practicas.', NULL, 'FLB', NULL, NULL, 'Equipo FLB10.1', 'Equipo FLB10.1', NULL, '2026-06-17 11:22:16.861594'),
	(2, b'1', 'Hidraulica', NULL, 'HY100', '2026-06-17 11:22:16.867591', 'Producto demo para manual de practicas de hidraulica.', 'Producto demo para manual de practicas de hidraulica.', NULL, 'HY', NULL, NULL, 'Equipo HY100', 'Equipo HY100', NULL, '2026-06-17 11:22:16.867591'),
	(3, b'1', 'A - Fundamentos de Mecánica de Fluidos', 'A', 'FL 01.1', '2026-06-23 13:11:08.000000', 'Unidad autónoma, portátil y económica de suministro de energía hidráulica para alimentar equipos didácticos de laboratorio.', 'Unidad autónoma, portátil y económica de suministro de energía hidráulica para alimentar equipos didácticos de laboratorio.', NULL, 'FL - Mecánica de fluidos', 'FL', 1, 'Grupo Hidráulico', 'Grupo Hidráulico', NULL, '2026-06-23 13:11:08.000000'),
	(4, b'1', 'A - Fundamentos de Mecánica de Fluidos', 'A', 'FL 01.2', '2026-06-23 13:11:08.000000', 'Set de cuatro placas de vertedero para estudiar la medida de caudal y el comportamiento de la lámina de agua en canal.', 'Set de cuatro placas de vertedero para estudiar la medida de caudal y el comportamiento de la lámina de agua en canal.', NULL, 'FL - Mecánica de fluidos', 'FL', 1, 'Flujo sobre Vertederos', 'Flujo sobre Vertederos', NULL, '2026-06-23 13:11:08.000000'),
	(5, b'1', 'A - Fundamentos de Mecánica de Fluidos', 'A', 'FL 01.3', '2026-06-23 13:11:08.000000', 'Banco para estudiar propiedades y fenómenos de la estática de fluidos, como densidad, presión, capilaridad, viscosidad y flotabilidad.', 'Banco para estudiar propiedades y fenómenos de la estática de fluidos, como densidad, presión, capilaridad, viscosidad y flotabilidad.', NULL, 'FL - Mecánica de fluidos', 'FL', 1, 'Banco Hidrostático', 'Banco Hidrostático', NULL, '2026-06-23 13:11:08.000000'),
	(6, b'1', 'A - Fundamentos de Mecánica de Fluidos', 'A', 'FL 01.4', '2026-06-23 13:11:08.000000', 'Banco hidráulico diseñado como mesa de trabajo para instalar equipos didácticos que necesitan aporte de caudal.', 'Banco hidráulico diseñado como mesa de trabajo para instalar equipos didácticos que necesitan aporte de caudal.', NULL, 'FL - Mecánica de fluidos', 'FL', 1, 'Banco Hidráulico', 'Banco Hidráulico', NULL, '2026-06-23 13:11:08.000000'),
	(7, b'1', 'A - Fundamentos de Mecánica de Fluidos', 'A', 'FL 01.6', '2026-06-23 13:11:08.000000', 'Banco hidráulico de 250 litros para alimentar equipos didácticos y medir caudales mediante depósitos volumétricos.', 'Banco hidráulico de 250 litros para alimentar equipos didácticos y medir caudales mediante depósitos volumétricos.', NULL, 'FL - Mecánica de fluidos', 'FL', 1, 'Banco Hidráulico 250L', 'Banco Hidráulico 250L', NULL, '2026-06-23 13:11:08.000000'),
